/// Kept exactly as the original's own non-power-of-2, overlapping
/// values (`ALL`/`BLOCK`/`INSERT` are NOT independent bits: `ALL = 0x04`,
/// `BLOCK = 0x05`, `INSERT = 0x06` overlap bit `0x04`/`0x01`/`0x02`
/// respectively) - this is how upstream really defines them, not a
/// translation error.
pub mod opt_ve_flag {
    pub const ALL: u32 = 0x04;
    pub const BLOCK: u32 = 0x05;
    pub const INSERT: u32 = 0x06;
    pub const ONEMORE: u32 = 0x08;
    pub const NONE: u32 = 0x10;
    pub const NONE_U: u32 = 0x20;
}

/// flags from `'wildmode'` (`OptWimFlags`).
pub mod opt_wim_flag {
    pub const FULL: u32 = 0x01;
    pub const LONGEST: u32 = 0x02;
    pub const LIST: u32 = 0x04;
    pub const LASTUSED: u32 = 0x08;
    pub const NOSELECT: u32 = 0x10;
    pub const NOINSERT: u32 = 0x20;
}

/// flags from `'wildoptions'` (`OptWopFlags`).
pub mod opt_wop_flag {
    pub const FUZZY: u32 = 0x01;
    pub const TAGFILE: u32 = 0x02;
    pub const PUM: u32 = 0x04;
    pub const EXACTTEXT: u32 = 0x08;
}

