/// The single, global, mutable option-value state instance - the Rust
/// equivalent of `option_vars.h`'s `EXTERN` mechanism, following exactly
/// the same pattern as `crate::globals::GLOBALS` (see that static's own
/// doc comment for the full reasoning: preserves the original's
/// implicit, no-parameter global access at every call site via
/// `crate::globals::GlobalCell`, rather than a bare `static mut`
/// reference or a `Mutex`/`RefCell` that could newly panic/deadlock on
/// reentrant access the original never worried about).
pub static OPTION_VARS: std::sync::LazyLock<crate::globals::GlobalCell<OptionVars>> =
    std::sync::LazyLock::new(|| crate::globals::GlobalCell::new(OptionVars::default()));

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn fo_all_combines_expected_flags() {
        assert_eq!(FO_ALL, "tcro/q2vlb1mMBn,aw]jp");
    }

    #[test]
    fn cpo_vim_and_vi_defaults_are_distinct() {
        assert_ne!(CPO_VIM, CPO_VI);
    }

    #[test]
    fn shm_all_abbreviations_matches_c_macro() {
        assert_eq!(SHM_ALL_ABBREVIATIONS, [b'r', b'm', b'l', b'w']);
    }

    #[test]
    fn max_stcwidth_matches_c_macro_expansion() {
        // MAX_NUMBERWIDTH + SIGN_SHOW_MAX * SIGN_WIDTH + 9 = 20 + 9*2 + 9
        assert_eq!(MAX_STCWIDTH, 20 + 9 * 2 + 9);
    }

    #[test]
    fn eol_constants_match_c_macros() {
        assert_eq!(EOL_UNKNOWN, -1);
        assert_eq!(EOL_UNIX, 0);
        assert_eq!(EOL_DOS, 1);
        assert_eq!(EOL_MAC, 2);
    }

    #[test]
    fn scl_constants_match_c_macros() {
        assert_eq!(SCL_NO, -1);
        assert_eq!(SCL_NUM, -2);
    }

    #[test]
    fn opt_bkc_flag_bits_are_distinct() {
        let all = [
            opt_bkc_flag::YES,
            opt_bkc_flag::AUTO,
            opt_bkc_flag::NO,
            opt_bkc_flag::BREAKSYMLINK,
            opt_bkc_flag::BREAKHARDLINK,
        ];
        let mut seen = 0;
        for f in all {
            assert_eq!(seen & f, 0);
            seen |= f;
        }
    }

    #[test]
    fn opt_ve_flag_matches_upstream_overlapping_values() {
        // Deliberately overlapping, verified against option_vars.generated.h.
        assert_eq!(opt_ve_flag::ALL, 0x04);
        assert_eq!(opt_ve_flag::BLOCK, 0x05);
        assert_eq!(opt_ve_flag::INSERT, 0x06);
    }

    #[test]
    fn value_arrays_have_expected_lengths() {
        assert_eq!(OPT_AMBW_VALUES.len(), 2);
        assert_eq!(OPT_BO_VALUES.len(), 20);
        assert_eq!(OPT_SCL_VALUES.len(), 22);
        assert_eq!(OPT_SSOP_VALUES.len(), 18);
    }

    #[test]
    fn empty_string_option_is_empty() {
        assert_eq!(EMPTY_STRING_OPTION, b"");
    }

    #[test]
    fn no_local_undolevel_matches_c_macro() {
        assert_eq!(NO_LOCAL_UNDOLEVEL, -123_456);
    }
}
